async (params, browser) => {
  // Open Discogs search
  await browser.open(`https://www.discogs.com/search/?q=${params.query}&type=all`)

  // Wait for results
  await browser.waitForSelector('#search_results, .card, .content', 15000)

  // Let results render
  await browser.wait(2500)

  // Extract results
  const search_results = await browser.evaluate(`const results = []; document.querySelectorAll('#search_results .card, .search_result_card, [data-object-type]').forEach((el, i) => { if (i < 15) { const titleEl = el.querySelector('a.search_result_title, h4 a, .card-title a'); const subtitleEl = el.querySelector('.card-subtitle, .search_result_subtitle, span'); results.push({ title: titleEl?.textContent?.trim() || '', url: titleEl?.href || '', subtitle: subtitleEl?.textContent?.trim() || '' }); } }); return { query: '' + params.query + '', result_count: results.length, results };`)

  return search_results
}
